import 'dotenv/config';
import { sendMessage } from './feishu/message.js';
import { generateDoc } from './commands/doc.js';
import { generateDiagram } from './commands/diagram.js';

const args = process.argv.slice(2);
const cmd = args[0];

function usage() {
  console.log(`
飞书机器人 CLI

用法:
  node src/index.js send <chat_id> <消息内容>
    发送文本消息到指定群聊

  node src/index.js doc <模板> <标题> [--chat <chat_id>]
    生成飞书文档并同步内容
    模板: meeting | tech | project

  node src/index.js diagram <类型> [--title <标题>] [--chat <chat_id>] [--doc]
    生成图表图片并发送到群聊
    类型: flowchart | sequence | classDiagram | gantt | pie | er

示例:
  node src/index.js send oc_xxx "Hello from bot!"
  node src/index.js doc meeting "周会纪要" --chat oc_xxx
  node src/index.js diagram flowchart "用户登录流程" --chat oc_xxx --doc
  `);
}

// 简单参数解析
function parseOpts(args) {
  const opts = {};
  const positional = [];
  for (let i = 0; i < args.length; i++) {
    if (args[i].startsWith('--')) {
      const key = args[i].slice(2);
      const val = args[i + 1] && !args[i + 1].startsWith('--') ? args[++i] : true;
      opts[key] = val;
    } else {
      positional.push(args[i]);
    }
  }
  return { opts, positional };
}

async function main() {
  if (!process.env.FEISHU_APP_ID || !process.env.FEISHU_APP_SECRET) {
    console.error('请先设置 .env 文件中的 FEISHU_APP_ID 和 FEISHU_APP_SECRET');
    process.exit(1);
  }

  if (!cmd || cmd === 'help' || cmd === '--help' || cmd === '-h') {
    usage();
    return;
  }

  try {
    switch (cmd) {
      case 'send': {
        const chatId = args[1];
        const msg = args.slice(2).join(' ');
        if (!chatId || !msg) {
          console.error('用法: node src/index.js send <chat_id> <消息内容>');
          process.exit(1);
        }
        console.log(`发送消息到 ${chatId}...`);
        const res = await sendMessage(chatId, msg);
        console.log('发送成功:', res?.data?.message_id);
        break;
      }

      case 'doc': {
        const { opts, positional } = parseOpts(args.slice(1));
        const template = positional[0];
        const title = positional[1];
        if (!template || !title) {
          console.error('用法: node src/index.js doc <模板> <标题> [--chat <chat_id>]');
          console.error(`模板: meeting | tech | project`);
          process.exit(1);
        }
        await generateDoc({
          template,
          title,
          chatId: opts.chat,
        });
        break;
      }

      case 'diagram': {
        const { opts, positional } = parseOpts(args.slice(1));
        const type = positional[0];
        const title = positional[1] || opts.title;
        if (!type) {
          console.error('用法: node src/index.js diagram <类型> [--title <标题>] [--chat <chat_id>] [--doc]');
          console.error(`类型: flowchart | sequence | classDiagram | gantt | pie | er`);
          process.exit(1);
        }
        await generateDiagram({
          type,
          title,
          chatId: opts.chat,
          toDoc: !!opts.doc,
        });
        break;
      }

      default:
        console.error(`未知命令: ${cmd}`);
        usage();
        process.exit(1);
    }
  } catch (err) {
    console.error('执行失败:', err.message);
    process.exit(1);
  }
}

main();

