import 'dotenv/config';

const SERVER = process.env.SERVER_URL;   // Render 部署后的 URL
const SECRET = process.env.SECRET || 'claude-feishu-bridge';
const CHAT_ID = 'oc_77f9b2ffb922311b80e503c6573e74f0';

async function call(path, body) {
  const url = `${SERVER}${path}`;
  const opts = {
    headers: { 'Content-Type': 'application/json', 'x-secret': SECRET },
  };
  if (body) {
    opts.method = 'POST';
    opts.body = JSON.stringify(body);
  }
  const res = await fetch(url, opts);
  return res.json();
}

/** 拉取飞书消息 */
async function fetchMessages() {
  const data = await call('/queue');
  return data.messages || [];
}

/** 发送消息到飞书群 */
async function sendToFeishu(text, chatId = CHAT_ID) {
  console.log(`发送到飞书: ${text.slice(0, 50)}...`);
  return call('/send', { chatId, text });
}

/** 创建飞书文档 */
async function createDoc(title, blocks, chatId = CHAT_ID) {
  console.log(`创建文档: ${title}`);
  return call('/doc/create', { title, blocks, chatId });
}

/** 创建图表 */
async function createDiagram(mermaid, title, chatId = CHAT_ID) {
  console.log(`创建图表: ${title || 'chart'}`);
  return call('/diagram/create', { mermaid, title, chatId });
}

export { fetchMessages, sendToFeishu, createDoc, createDiagram };

