2	import express from 'express';
3	import crypto from 'node:crypto';
4	
5	const app = express();
6	app.use(express.json());
7	
8	const PORT = process.env.PORT || 3000;
9	const APP_ID = process.env.FEISHU_APP_ID;
10	const APP_SECRET = process.env.FEISHU_APP_SECRET;
11	const SECRET = process.env.SECRET || 'claude-feishu-bridge'; // Claude Code 调 API 用的秘钥
12	
13	// ─── 消息队列（Render 持久运行，内存存储安全）───────────────
14	let messageQueue = [];
