16	// ─── 飞书 API 工具 ─────────────────────────────────────────
17	
18	async function getToken() {
19	  const res = await fetch(
20	    'https://open.feishu.cn/open-apis/auth/v3/tenant_access_token/internal',
21	    {
22	      method: 'POST',
23	      headers: { 'Content-Type': 'application/json' },
24	      body: JSON.stringify({ app_id: APP_ID, app_secret: APP_SECRET }),
25	    }
26	  );
27	  return (await res.json()).tenant_access_token;
28	}
29	
30	async function sendFeishuMsg(token, chatId, text) {
31	  const res = await fetch(
32	    'https://open.feishu.cn/open-apis/im/v1/messages?receive_id_type=chat_id',
33	    {
34	      method: 'POST',
35	      headers: {
36	        Authorization: `Bearer ${token}`,
37	        'Content-Type': 'application/json',
38	      },
39	      body: JSON.stringify({
40	        receive_id: chatId,
41	        msg_type: 'text',
42	        content: JSON.stringify({ text }),
43	      }),
44	    }
45	  );
46	  return res.json();
47	}
48	
49	async function createFeishuDoc(token, title) {
50	  const res = await fetch(
51	    'https://open.feishu.cn/open-apis/docx/v1/documents',
52	    {
53	      method: 'POST',
54	      headers: {
55	        Authorization: `Bearer ${token}`,
56	        'Content-Type': 'application/json',
57	      },
58	      body: JSON.stringify({ title }),
59	    }
60	  );
61	  const data = await res.json();
62	  const docId = data?.data?.document?.document_id;
63	  return { documentId: docId, url: `https://bytedance.feishu.cn/docx/${docId}` };
64	}
65	
66	async function appendDocBlocks(token, docId, blockId, blocks) {
67	  return fetch(
68	    `https://open.feishu.cn/open-apis/docx/v1/documents/${docId}/blocks/${blockId}/children`,
69	    {
70	      method: 'POST',
71	      headers: {
72	        Authorization: `Bearer ${token}`,
73	        'Content-Type': 'application/json',
74	      },
75	      body: JSON.stringify({ children: blocks }),
76	    }
77	  );
78	}
79	
80	async function uploadImageToFeishu(token, imageBuffer) {
81	  const formData = new FormData();
82	  formData.append('image_type', 'message');
83	  formData.append('image', new Blob([imageBuffer]), 'image.png');
84	
85	  const res = await fetch('https://open.feishu.cn/open-apis/im/v1/images', {
86	    method: 'POST',
87	    headers: { Authorization: `Bearer ${token}` },
88	    body: formData,
89	  });
90	  const data = await res.json();
91	  return data?.data?.image_key;
92	}
93	
94	// ─── 签名校验 ──────────────────────────────────────────────
95	
96	function verifySignature(timestamp, nonce, body) {
97	  const raw = [timestamp, nonce, '', APP_SECRET].join('');
98	  return crypto.createHash('sha256').update(raw).digest('hex');
99	}
100	
101	// ─── 中间件：鉴权（保护内部 API）────────────────────────────
102	
103	function auth(req, res, next) {
104	  const provided = req.headers['x-secret'] || req.query.secret;
105	  if (provided !== SECRET) {
106	    return res.status(403).json({ error: 'unauthorized' });
107	  }
108	  next();
109	}
110	
111	// ─── 飞书事件回调 ──────────────────────────────────────────
112	
113	app.post('/feishu/event', (req, res) => {
114	  const body = req.body;
115	
116	  // URL 验证
117	  if (body?.type === 'url_verification') {
118	    console.log('URL verification OK');
119	    return res.json({ challenge: body.challenge });
120	  }
121	
122	  // 签名校验
123	  const timestamp = req.headers['x-lark-request-timestamp'] || '';
124	  const nonce = req.headers['x-lark-request-nonce'] || '';
125	  const signature = req.headers['x-lark-signature'] || '';
126	
127	  if (signature) {
128	    const expected = verifySignature(timestamp, nonce, JSON.stringify(body));
129	    if (signature !== expected) {
130	      return res.status(401).json({ msg: 'invalid signature' });
131	    }
132	  }
133	
134	  // 立即返回 200
135	  res.json({ code: 0 });
136	
137	  // 处理消息
138	  const event = body?.event;
139	  if (!event || event.type !== 'im.message.receive_v1') return;
140	
141	  const msg = event.message;
142	  if (!msg || msg.message_type !== 'text') return;
143	
144	  let text = '';
145	  try { text = JSON.parse(msg.content).text?.trim(); } catch { return; }
146	  if (!text) return;
147	
148	  console.log(`[飞书消息] ${text} | chat: ${msg.chat_id}`);
149	
150	  messageQueue.push({
151	    id: Date.now().toString(36) + Math.random().toString(36).slice(2, 8),
152	    chatId: msg.chat_id,
153	    text,
154	    time: new Date().toISOString(),
155	  });
156	
157	  if (messageQueue.length > 100) messageQueue = messageQueue.slice(-100);
158	});
159	
160	// ─── Claude Code 接口 ──────────────────────────────────────
161	
162	// 拉取消息（Claude Code 轮询这个接口）
163	app.get('/queue', auth, (req, res) => {
164	  const msgs = [...messageQueue];
165	  messageQueue = [];
166	  res.json({ messages: msgs });
167	});
168	
169	// 发消息到飞书群
170	app.post('/send', auth, async (req, res) => {
171	  const { chatId, text } = req.body;
172	  if (!chatId || !text) return res.status(400).json({ error: 'chatId and text required' });
173	  try {
174	    const token = await getToken();
175	    const result = await sendFeishuMsg(token, chatId, text);
176	    res.json(result);
177	  } catch (e) {
178	    res.status(500).json({ error: e.message });
179	  }
180	});
181	
182	// 创建飞书文档
183	app.post('/doc/create', auth, async (req, res) => {
184	  const { title, blocks, chatId } = req.body;
185	  if (!title) return res.status(400).json({ error: 'title required' });
186	  try {
187	    const token = await getToken();
188	    const doc = await createFeishuDoc(token, title);
189	    if (blocks?.length) {
190	      await appendDocBlocks(token, doc.documentId, doc.documentId, blocks);
191	    }
192	    if (chatId) {
193	      await sendFeishuMsg(token, chatId, `文档已生成: ${doc.url}`);
194	    }
195	    res.json(doc);
196	  } catch (e) {
197	    res.status(500).json({ error: e.message });
198	  }
199	});
200	
201	// 生成 Mermaid 图表并上传
202	app.post('/diagram/create', auth, async (req, res) => {
203	  const { mermaid, title, chatId } = req.body;
204	  if (!mermaid) return res.status(400).json({ error: 'mermaid code required' });
205	  try {
206	    const token = await getToken();
207	    // 调用 mermaid.ink 渲染
208	    const encoded = Buffer.from(mermaid).toString('base64');
209	    const imgRes = await fetch(`https://mermaid.ink/img/${encoded}?type=png`);
210	    if (!imgRes.ok) throw new Error(`Mermaid render failed: ${imgRes.status}`);
211	    const imgBuf = Buffer.from(await imgRes.arrayBuffer());
212	    const imageKey = await uploadImageToFeishu(token, imgBuf);
213	
214	    // 发到群
215	    if (chatId) {
216	      await fetch(
217	        `https://open.feishu.cn/open-apis/im/v1/messages?receive_id_type=chat_id`,
218	        {
219	          method: 'POST',
220	          headers: {
221	            Authorization: `Bearer ${token}`,
222	            'Content-Type': 'application/json',
223	          },
224	          body: JSON.stringify({
