226	            msg_type: 'image',
227	            content: JSON.stringify({ image_key: imageKey }),
228	          }),
229	        }
230	      );
231	    }
232	
233	    // 创建文档
234	    let docUrl;
235	    if (title) {
236	      const doc = await createFeishuDoc(token, title);
237	      await appendDocBlocks(token, doc.documentId, doc.documentId, [
238	        {
239	          block_type: 27,
240	          image: { token: imageKey },
241	        },
242	      ]);
243	      docUrl = doc.url;
244	    }
245	
246	    res.json({ imageKey, docUrl });
247	  } catch (e) {
248	    res.status(500).json({ error: e.message });
249	  }
250	});
