import requests
import json
import time
import os
import sys

APP_ID = "cli_a9775595ac799bb4"
APP_SECRET = "[REDACTED]"
CHAT_ID = "oc_77f9b2ffb922311b80e503c6573e74f0"

BASE = os.path.dirname(os.path.abspath(__file__))
LAST_FILE = os.path.join(BASE, "..", ".last_msg_id")
QUEUE_FILE = os.path.join(BASE, "..", "message_queue.json")


def get_token():
    resp = requests.post(
        "https://open.feishu.cn/open-apis/auth/v3/tenant_access_token/internal",
        json={"app_id": APP_ID, "app_secret": APP_SECRET},
    )
    return resp.json()["tenant_access_token"]


def get_latest_message_id(token):
    """获取群聊最新一条消息的 ID"""
    resp = requests.get(
        "https://open.feishu.cn/open-apis/im/v1/messages",
        headers={"Authorization": f"Bearer {token}"},
        params={
            "container_id_type": "chat",
            "container_id": CHAT_ID,
            "page_size": 1,
            "sort_type": "ByCreateTimeDesc",
        },
    )
    items = resp.json().get("data", {}).get("items", [])
    return items[0]["message_id"] if items else None


def fetch_new_messages(token, since_id):
    """获取 since_id 之后的新消息，使用分页"""
    new_msgs = []
    page_token = None

    while True:
        params = {
            "container_id_type": "chat",
            "container_id": CHAT_ID,
            "page_size": 20,
            "sort_type": "ByCreateTimeDesc",
        }
        if page_token:
            params["page_token"] = page_token

        resp = requests.get(
            "https://open.feishu.cn/open-apis/im/v1/messages",
            headers={"Authorization": f"Bearer {token}"},
            params=params,
        )
        data = resp.json()
        items = data.get("data", {}).get("items", [])

        for msg in items:
            if msg["message_id"] == since_id:
                return new_msgs  # 遇到上次处理的消息，停止
            new_msgs.append(msg)

        if not data.get("data", {}).get("has_more"):
            break
        page_token = data["data"].get("page_token")

    return new_msgs


def send_message(token, text):
    resp = requests.post(
        "https://open.feishu.cn/open-apis/im/v1/messages?receive_id_type=chat_id",
        headers={
            "Authorization": f"Bearer {token}",
            "Content-Type": "application/json",
        },
        json={
            "receive_id": CHAT_ID,
            "msg_type": "text",
            "content": json.dumps({"text": text}, ensure_ascii=False),
        },
    )
    return resp.json()


OUR_BOT_OPEN_ID = "ou_4f25325a2830b36f02aba6d80ab8cdec"

def get_text(msg):
    if msg.get("msg_type") != "text":
        return None
    body = msg.get("body", {}).get("content", "{}")
    try:
        return json.loads(body).get("text", "").strip()
    except:
        return body.strip()


def is_mentioning_us(msg):
    """通过 mentions 字段精确判断是否 @了我们的机器人"""
    mentions = msg.get("mentions", [])
    return any(m.get("id") == OUR_BOT_OPEN_ID for m in mentions)


def quick_reply(text):
    """简单问题自动回复"""
    # 去除 @机器人 前缀
    t = text.lower()
    # 尝试去掉各种 @前缀
    for prefix in ["@_user_1", "@claude code"]:
        t = t.replace(prefix, "")
    t = t.strip()
    if t in ["你好", "hello", "hi", "在吗", "在不在"]:
        return "你好！我是 Claude 助手，随时帮您写文档、画图表、答问题。直接发需求就好！"
    if t in ["帮助", "help", "功能"]:
        return "支持：\n📄 写文档\n📊 画图表\n💬 问答\n\n直接发消息即可！"
    return None


def queue_message(msg):
    """将无法自动回复的消息写入队列"""
    entry = {
        "message_id": msg.get("message_id"),
        "text": get_text(msg),
        "sender": msg.get("sender", {}).get("id"),
        "time": msg.get("create_time"),
        "processed": False,
    }
    queue = []
    if os.path.exists(QUEUE_FILE):
        try:
            with open(QUEUE_FILE) as f:
                queue = json.load(f)
        except:
            pass
    # 去重
    if not any(m.get("message_id") == entry["message_id"] for m in queue):
        queue.append(entry)
    if len(queue) > 100:
        queue = queue[-100:]
    with open(QUEUE_FILE, "w") as f:
        json.dump(queue, f, ensure_ascii=False, indent=2)


def main():
    token = get_token()

    # 启动时记录最新消息，之后只处理更新的
    last_id = get_latest_message_id(token)
    if last_id:
        with open(LAST_FILE, "w") as f:
            f.write(last_id)
        print(f"已就位，跳过历史消息 (last_id: {last_id[:20]}...)")
    else:
        print("警告：无法获取群消息")

    print("开始轮询 (间隔 5 秒)...\n")

    while True:
        try:
            token = get_token()

            # 读取上次处理到的消息 ID
            try:
                with open(LAST_FILE) as f:
                    since_id = f.read().strip()
            except:
                since_id = None

            if not since_id:
                time.sleep(5)
                continue

            new_msgs = fetch_new_messages(token, since_id)

            if new_msgs:
                # 从旧到新处理
                for msg in reversed(new_msgs):
                    text = get_text(msg)
                    if not text:
                        continue

                    # 精确匹配：只处理 @了我们机器人的消息
                    if not is_mentioning_us(msg):
                        continue

                    clean = text.replace(OUR_BOT_MENTION, "").strip()
                    print(f"[{msg['message_id'][:12]}...] {clean[:60]}")

                    reply = quick_reply(text)
                    if reply:
                        send_message(token, reply)
                        print(f"  → 自动回复")
                    else:
                        queue_message(msg)
                        print(f"  → 已加入队列")

                    time.sleep(0.3)

                # 更新已处理到最新消息
                new_last = new_msgs[0]["message_id"]
                with open(LAST_FILE, "w") as f:
                    f.write(new_last)

            time.sleep(5)

        except KeyboardInterrupt:
            print("\n已停止")
            break
        except Exception as e:
            print(f"轮询错误: {e}", file=sys.stderr)
            time.sleep(10)


if __name__ == "__main__":
    main()

