import sys
import subprocess
import uuid

APP_ID = "cli_a9775595ac799bb4"
APP_SECRET = "[REDACTED]"
CHAT_ID = "oc_77f9b2ffb922311b80e503c6573e74f0"

BASE = os.path.dirname(os.path.abspath(__file__))
ROOT = os.path.join(BASE, "..")
LAST_FILE = os.path.join(ROOT, ".last_msg_id")
