            new_msgs = fetch_new_messages(token, since_id)

            if new_msgs:
                for msg in reversed(new_msgs):
                    text = get_text(msg)
                    if not text:
                        continue

                    if not is_mentioning_us(msg):
                        continue

                    clean = text.replace(OUR_BOT_MENTION, "").strip()
                    print(f"[{msg['message_id'][:12]}...] {clean[:60]}")

                    reply = quick_reply(text)
                    if reply:
                        send_message(token, reply)
                        print(f"  → 自动回复")
                    else:
                        print(f"  → 调用 Claude Code 生成回复...")
                        claude_reply = call_claude(
                            text,
                            sender_name=msg.get("sender", {}).get("id", ""),
                        )
                        if claude_reply:
                            send_message(token, claude_reply)
                            print(f"  → Claude 已回复")
                        else:
                            send_message(token, "抱歉，我暂时无法处理这条消息，请稍后再试。")
                            print(f"  → 回复失败，已发送兜底消息")

                    time.sleep(0.3)

                new_last = new_msgs[0]["message_id"]
                with open(LAST_FILE, "w") as f:
                    f.write(new_last)

            time.sleep(5)

        except KeyboardInterrupt:
            print("\n已停止")
            break
        except Exception as e:
            print(f"轮询错误: {e}", file=sys.stderr)
            time.sleep(10)


if __name__ == "__main__":
    if len(sys.argv) > 1 and sys.argv[1] == "reset":
        reset_session()
    else:
