    for prefix in ["@_user_1", "@claude code"]:
        t = t.replace(prefix, "")
    t = t.strip()
    if t in ["你好", "hello", "hi", "在吗", "在不在"]:
        return "你好！我是 Claude 助手，随时帮您写文档、画图表、答问题。直接发需求就好！"
    if t in ["帮助", "help", "功能"]:
        return "支持：\n📄 写文档\n📊 画图表\n💬 问答\n\n直接发消息即可！"
    return None


def call_claude(user_message, sender_name=""):
    """调用 Claude Code CLI 生成回复，支持会话连续性"""
    clean_msg = user_message
    for prefix in ["@_user_1", "@claude code"]:
        clean_msg = clean_msg.replace(prefix, "")
    clean_msg = clean_msg.strip()

    prompt = f"""飞书群里有人 @你 发了消息，你需要回复他。

发消息的人：{sender_name or '群成员'}
消息内容：{clean_msg}

请直接回复，简洁有用。如果用户请你执行操作（写文档、画图表、查资料等），直接做，做完告诉用户结果。
回复要自然，像在群里聊天一样。使用中文。"""

    cmd = ["claude", "-p", prompt,
           "--output-format", "text",
           "--add-dir", ROOT,
           "--no-session-persistence"]

    if os.path.exists(SESSION_FILE):
        with open(SESSION_FILE) as f:
            session_id = f.read().strip()
        if session_id:
            cmd += ["--resume", session_id]
    else:
        session_id = str(uuid.uuid4())
        with open(SESSION_FILE, "w") as f:
            f.write(session_id)
        cmd += ["--session-id", session_id]

    try:
        result = subprocess.run(
            cmd,
            capture_output=True, text=True,
            timeout=120,
            cwd=ROOT,
        )
        reply = result.stdout.strip()
        if result.returncode != 0 or not reply:
            print(f"  Claude 调用失败: {result.stderr[:200] if result.stderr else '无输出'}")
            return None
        return reply
    except subprocess.TimeoutExpired:
        print("  Claude 调用超时")
        return None
    except Exception as e:
        print(f"  Claude 调用异常: {e}")
        return None


def reset_session():
    """重置对话会话"""
    if os.path.exists(SESSION_FILE):
        os.remove(SESSION_FILE)
    print("对话会话已重置")


def main():
    token = get_token()

    last_id = get_latest_message_id(token)
    if last_id:
        with open(LAST_FILE, "w") as f:
            f.write(last_id)
        print(f"已就位，跳过历史消息 (last_id: {last_id[:20]}...)")
    else:
        print("警告：无法获取群消息")

    print("开始轮询 (间隔 5 秒)...")
    print(f"Claude 会话: {'续接' if os.path.exists(SESSION_FILE) else '新建'}\n")

    while True:
        try:
            token = get_token()

            try:
                with open(LAST_FILE) as f:
                    since_id = f.read().strip()
            except:
                since_id = None

            if not since_id:
                time.sleep(5)
                continue

            new_msgs = fetch_new_messages(token, since_id)

            if new_msgs:
                for msg in reversed(new_msgs):
                    text = get_text(msg)
                    if not text:
                        continue

                    if not is_mentioning_us(msg):
                        continue

                    clean = text.replace(OUR_BOT_MENTION, "").strip()
                    print(f"[{msg['message_id'][:12]}...] {clean[:60]}")

                    reply = quick_reply(text)
                    if reply:
                        send_message(token, reply)
                        print(f"  → 自动回复")
                    else:
                        print(f"  → 调用 Claude Code 生成回复...")
                        claude_reply = call_claude(
                            text,
                            sender_name=msg.get("sender", {}).get("id", ""),
                        )
                        if claude_reply:
                            send_message(token, claude_reply)
                            print(f"  → Claude 已回复")
                        else:
                            send_message(token, "抱歉，我暂时无法处理这条消息，请稍后再试。")
                            print(f"  → 回复失败，已发送兜底消息")

                    time.sleep(0.3)

                new_last = new_msgs[0]["message_id"]
                with open(LAST_FILE, "w") as f:
                    f.write(new_last)

            time.sleep(5)

        except KeyboardInterrupt:
            print("\n已停止")
            break
        except Exception as e:
            print(f"轮询错误: {e}", file=sys.stderr)
            time.sleep(10)


if __name__ == "__main__":
    if len(sys.argv) > 1 and sys.argv[1] == "reset":
        reset_session()
    else:
        main()

