import client from './client.js';

/**
 * 发送文本消息到飞书群或用户
 * @param {string} receiveId - 接收者 ID（群 chat_id 或用户 open_id）
 * @param {string} content - 消息内容（JSON 格式的飞书消息体）
 * @returns {Promise<object>} 发送结果
 */
export async function sendMessage(receiveId, content) {
  return client.im.message.create({
    params: { receive_id_type: 'chat_id' },
    data: {
      receive_id: receiveId,
      msg_type: 'text',
      content: JSON.stringify({ text: content }),
    },
  });
}

/**
 * 发送富文本/卡片消息
 * @param {string} receiveId - 接收者 ID
 * @param {string} content - JSON 字符串格式的消息体
 */
export async function sendInteractiveMessage(receiveId, content) {
  return client.im.message.create({
    params: { receive_id_type: 'chat_id' },
    data: {
      receive_id: receiveId,
      msg_type: 'interactive',
      content,
    },
  });
}

/**
 * 发送图片消息
 * @param {string} receiveId - 接收者 ID
 * @param {string} imageKey - 上传图片后拿到的 image_key
 */
export async function sendImageMessage(receiveId, imageKey) {
  return client.im.message.create({
    params: { receive_id_type: 'chat_id' },
    data: {
      receive_id: receiveId,
      msg_type: 'image',
      content: JSON.stringify({ image_key: imageKey }),
    },
  });
}

/**
 * 发送文件消息
 * @param {string} receiveId - 接收者 ID
 * @param {string} fileKey - 上传文件后拿到的 file_key
 */
export async function sendFileMessage(receiveId, fileKey) {
  return client.im.message.create({
    params: { receive_id_type: 'chat_id' },
    data: {
      receive_id: receiveId,
      msg_type: 'file',
      content: JSON.stringify({ file_key: fileKey }),
    },
  });
}

"""
飞书消息轮询 + Claude Code 自动回复
持续运行，检测新消息并通过 claude -p 生成回复
支持文字消息和语音消息（语音 → ASR 转写 → 处理）
"""
import requests
from requests.adapters import HTTPAdapter
from urllib3.util.retry import Retry
import json
import time
import os
import sys
import subprocess
import uuid
import tempfile

APP_ID = "cli_a9775595ac799bb4"
APP_SECRET = "[REDACTED]"
CHAT_ID = "oc_77f9b2ffb922311b80e503c6573e74f0"

BASE = os.path.dirname(os.path.abspath(__file__))
ROOT = os.path.join(BASE, "..")
LAST_FILE = os.path.join(ROOT, ".last_msg_id")
SESSION_FILE = os.path.join(ROOT, ".claude_session_id")

OUR_BOT_OPEN_ID = "ou_4f25325a2830b36f02aba6d80ab8cdec"
OUR_BOT_MENTION = "@_user_1"


def _feishu_session():
    """创建带重试机制的 requests Session"""
    s = requests.Session()
    retry = Retry(
        total=3,
        backoff_factor=2,
        status_forcelist=[429, 500, 502, 503, 504],
    )
    adapter = HTTPAdapter(max_retries=retry)
    s.mount("https://", adapter)
    return s


def _api_get(session, url, **kwargs):
    """带重试的 GET 请求"""
    last_err = None
    for attempt in range(5):
        try:
            return session.get(url, timeout=30, **kwargs)
        except (requests.ConnectionError, requests.Timeout) as e:
            last_err = e
            wait = 2 ** attempt
            print(f"  网络错误 (第{attempt+1}次重试, {wait}s): {e}", file=sys.stderr)
            time.sleep(wait)
    raise last_err


def _api_post(session, url, **kwargs):
    """带重试的 POST 请求"""
    last_err = None
    for attempt in range(5):
        try:
            return session.post(url, timeout=30, **kwargs)
        except (requests.ConnectionError, requests.Timeout) as e:
            last_err = e
            wait = 2 ** attempt
            print(f"  网络错误 (第{attempt+1}次重试, {wait}s): {e}", file=sys.stderr)
            time.sleep(wait)
    raise last_err


_session = None


def get_session():
    global _session
    if _session is None:
        _session = _feishu_session()
    return _session


def get_token():
    resp = get_session().post(
        "https://open.feishu.cn/open-apis/auth/v3/tenant_access_token/internal",
        json={"app_id": APP_ID, "app_secret": APP_SECRET},
        timeout=30,
    )
    return resp.json()["tenant_access_token"]


def get_latest_message_id(token):
    resp = _api_get(get_session(),
        "https://open.feishu.cn/open-apis/im/v1/messages",
        headers={"Authorization": f"Bearer {token}"},
        params={
            "container_id_type": "chat",
            "container_id": CHAT_ID,
            "page_size": 1,
            "sort_type": "ByCreateTimeDesc",
        },
    )
    items = resp.json().get("data", {}).get("items", [])
    return items[0]["message_id"] if items else None


def fetch_new_messages(token, since_id):
    new_msgs = []
    page_token = None

    while True:
        params = {
            "container_id_type": "chat",
            "container_id": CHAT_ID,
            "page_size": 20,
            "sort_type": "ByCreateTimeDesc",
        }
        if page_token:
            params["page_token"] = page_token

        resp = _api_get(get_session(),
            "https://open.feishu.cn/open-apis/im/v1/messages",
            headers={"Authorization": f"Bearer {token}"},
            params=params,
        )
        data = resp.json()
        items = data.get("data", {}).get("items", [])

        for msg in items:
            if msg["message_id"] == since_id:
                return new_msgs
            new_msgs.append(msg)

        if not data.get("data", {}).get("has_more"):
            break
        page_token = data["data"].get("page_token")

    return new_msgs


def send_message(token, text):
    resp = _api_post(get_session(),
        "https://open.feishu.cn/open-apis/im/v1/messages?receive_id_type=chat_id",
        headers={
            "Authorization": f"Bearer {token}",
            "Content-Type": "application/json",
        },
        json={
            "receive_id": CHAT_ID,
            "msg_type": "text",
            "content": json.dumps({"text": text}, ensure_ascii=False),
        },
    )
    return resp.json()


def get_text(msg):
    if msg.get("msg_type") != "text":
        return None
    body = msg.get("body", {}).get("content", "{}")
    try:
        return json.loads(body).get("text", "").strip()
    except:
        return body.strip()


def is_mentioning_us(msg):
    mentions = msg.get("mentions", [])
