    t = text.lower().strip()
    # 匹配 "做X" / "帮我X" / "把X" 等操作意图
    for prefix in ["帮我", "帮我把", "给我", "把", "请"]:
        if t.startswith(prefix):
            return {"action": "general", "task": text}
    if t in ["你好", "hello", "hi", "在吗", "在不在", "帮助", "help", "功能"]:
        return None
    # 默认当作对话
    return None


def call_claude(user_message, sender_name=""):
    """调用 Claude Code CLI 生成回复，支持会话连续性"""
    clean_msg = user_message
    for prefix in ["@_user_1", "@claude code"]:
        clean_msg = clean_msg.replace(prefix, "")
    clean_msg = clean_msg.strip()

    prompt = f"""飞书群里有人 @你 发了消息，你需要回复他。

发消息的人：{sender_name or '群成员'}
消息内容：{clean_msg}

请直接回复，简洁有用。如果用户请你执行操作（写文档、画图表、查资料等），直接做，做完告诉用户结果。
回复要自然，像在群里聊天一样。使用中文。"""

    cmd = ["claude", "-p", prompt,
           "--output-format", "text",
           "--add-dir", ROOT,
           "--permission-mode", "bypassPermissions"]

    if os.path.exists(SESSION_FILE):
        with open(SESSION_FILE) as f:
            session_id = f.read().strip()
        if session_id:
            cmd += ["--resume", session_id]
    else:
        session_id = str(uuid.uuid4())
        with open(SESSION_FILE, "w") as f:
            f.write(session_id)
        cmd += ["--session-id", session_id]

    try:
        result = subprocess.run(
            cmd,
            capture_output=True, text=True,
            timeout=180,
            cwd=ROOT,
        )
        reply = result.stdout.strip()
        if result.returncode != 0 or not reply:
            print(f"  Claude 调用失败: {result.stderr[:200] if result.stderr else '无输出'}")
            return None
        return reply
    except subprocess.TimeoutExpired:
        print("  Claude 调用超时")
        return None
    except Exception as e:
        print(f"  Claude 调用异常: {e}")
        return None


def quick_reply(text):
