        except (requests.ConnectionError, requests.Timeout) as e:
            last_err = e
            wait = 2 ** attempt
            print(f"  网络错误 (第{attempt+1}次重试, {wait}s): {e}", file=sys.stderr)
            time.sleep(wait)
    raise last_err


