def _api_get(session, url, **kwargs):
    """带重试的 GET 请求"""
    last_err = None
    for attempt in range(5):
        try:
            return session.get(url, timeout=30, **kwargs)
        except (requests.ConnectionError, requests.Timeout) as e:
            last_err = e
            wait = 2 ** attempt
            print(f"  网络错误 (第{attempt+1}次重试, {wait}s): {e}", file=sys.stderr)
            time.sleep(wait)
    raise last_err


def _api_post(session, url, **kwargs):
    """带重试的 POST 请求"""
    last_err = None
    for attempt in range(5):
        try:
            return session.post(url, timeout=30, **kwargs)
        except (requests.ConnectionError, requests.Timeout) as e:
            last_err = e
            wait = 2 ** attempt
            print(f"  网络错误 (第{attempt+1}次重试, {wait}s): {e}", file=sys.stderr)
            time.sleep(wait)
    raise last_err


_session = None


def get_session():
