    data = resp.json()
    if data.get("code") != 0:
        print(f"  读取文档失败: {data.get('msg')}")
        return None

    blocks = data.get("data", {}).get("items", [])
    if not blocks:
        return None

    texts = []
    for block in blocks:
        block_type = block.get("block_type", 0)
        # block_type 2 = 文本块
        text_data = block.get("text", {})
        elements = text_data.get("elements", [])
        for elem in elements:
            run = elem.get("text_run", {})
            content = run.get("content")
            if content:
                texts.append(content)
        # 处理标题块等
        for key in ("heading1", "heading2", "heading3", "heading4", "heading5", "heading6", "heading7", "heading8", "heading9"):
            h = block.get(key, {})
